Javascript.validate:
var description = Services.getValue(REF_DATA_XPATH + "/WhichPartyLodgedTheAppealList/WhichPartyLodgedTheAppeal[./Value = " + AppealLodgedParty.dataBinding + "]/Description");
var valueTest = Services.getValue( REF_DATA_XPATH + "/WhichPartyLodgedTheAppealList/WhichPartyLodgedTheAppeal[./Description = " + AppealLodgedParty.dataBinding + "]/Value" );
if (description == null && valueTest == null)
{
	// This is not a valid value - see list of Values
	return ErrorCode.getErrorCode("CaseMan_Reports_Invalid_LOV_Msg");
}
else
{
	return null;
}

